import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

// Weather condition emoji map
const weatherEmojis: Record<string, string> = {
  sunny: '☀️',
  cloudy: '☁️',
  rainy: '🌧️',
  stormy: '⛈️',
  snowy: '❄️',
  foggy: '🌫️',
  windy: '💨',
  partlycloudy: '⛅',
  clear: '🌙',
  drizzle: '🌦️',
  sleet: '🧊',
};

interface ForecastDay {
  day: string;
  condition: string;
  high: number;
  low: number;
}

interface Props {
  // Current weather
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: 'C' | 'F';

  // 5-day forecast
  forecast?: ForecastDay[];

  // Callback
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', condition: 'sunny', high: 75, low: 62 },
    { day: 'Tue', condition: 'partlyCloudy', high: 73, low: 61 },
    { day: 'Wed', condition: 'rainy', high: 68, low: 58 },
    { day: 'Thu', condition: 'cloudy', high: 70, low: 60 },
    { day: 'Fri', condition: 'sunny', high: 76, low: 63 },
  ],
  onSubmit,
}: Props) {
  const [time, setTime] = useState<string>('');

  useEffect(() => {
    const updateTime = () => {
      setTime(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    };
    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  const getWeatherEmoji = (cond: string): string => {
    const normalized = cond.toLowerCase().replace(/\s+/g, '');
    return weatherEmojis[normalized] || weatherEmojis.cloudy;
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-md, 16px)">
      <Card shadow="md" padding="var(--ggui-spacing-lg, 24px)">
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <Stack direction="horizontal" justify="between" align="start">
            <Stack direction="vertical" gap={4}>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-900, #0c4a6e)"
                weight="bold"
              >
                {city}
              </Text>
              <Text
                color="var(--ggui-color-text-secondary, #6b7280)"
                variant="caption"
              >
                {time}
              </Text>
            </Stack>
          </Stack>

          {/* Current Temperature Section */}
          <Stack direction="vertical" gap={16} align="center">
            <div
              style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                lineHeight: '1.2',
              }}
            >
              {getWeatherEmoji(condition)}
            </div>
            <Stack direction="vertical" gap={4} align="center">
              <div
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                  color: 'var(--ggui-color-primary-700, #0369a1)',
                  letterSpacing: '-0.025em',
                }}
              >
                {Math.round(temperature)}°{unit}
              </div>
              <Text
                color="var(--ggui-color-text-primary, #111827)"
                variant="body"
                weight="medium"
              >
                {condition}
              </Text>
            </Stack>
          </Stack>

          {/* Current Conditions Grid */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: 'var(--ggui-spacing-md, 16px)',
              padding: 'var(--ggui-spacing-md, 16px)',
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-radius-md, 8px)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
            }}
          >
            {/* Humidity Card */}
            <Stack direction="vertical" gap={8} align="center">
              <Text
                color="var(--ggui-color-text-secondary, #6b7280)"
                variant="caption"
                weight="semibold"
              >
                HUMIDITY
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {humidity}%
              </div>
            </Stack>

            {/* Wind Speed Card */}
            <Stack direction="vertical" gap={8} align="center">
              <Text
                color="var(--ggui-color-text-secondary, #6b7280)"
                variant="caption"
                weight="semibold"
              >
                WIND SPEED
              </Text>
              <div
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                }}
              >
                {windSpeed} mph
              </div>
            </Stack>
          </div>

          <Divider margin={8} />

          {/* 5-Day Forecast */}
          <Stack direction="vertical" gap={12}>
            <Text
              variant="h3"
              weight="semibold"
              color="var(--ggui-color-primary-900, #0c4a6e)"
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip - Horizontal scrollable container */}
            <div
              style={{
                display: 'flex',
                gap: 'var(--ggui-spacing-sm, 8px)',
                overflowX: 'auto',
                paddingBottom: 'var(--ggui-spacing-sm, 8px)',
                scrollBehavior: 'smooth',
              }}
            >
              {forecast.map((day, index) => {
                const key = 'forecast_' + index;
                return (
                  <div
                    key={key}
                    style={{
                      flex: '0 0 auto',
                      minWidth: '100px',
                      padding: 'var(--ggui-spacing-md, 16px)',
                      backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                      border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                      borderRadius: 'var(--ggui-radius-md, 8px)',
                      textAlign: 'center',
                      transition: 'box-shadow 200ms ease-out, border-color 200ms ease-out',
                      cursor: 'pointer',
                    }}
                    onMouseEnter={(e) => {
                      const el = e.currentTarget as HTMLDivElement;
                      el.style.boxShadow = 'var(--ggui-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                      el.style.borderColor = 'var(--ggui-color-primary-400, #38bdf8)';
                    }}
                    onMouseLeave={(e) => {
                      const el = e.currentTarget as HTMLDivElement;
                      el.style.boxShadow = 'none';
                      el.style.borderColor = 'var(--ggui-color-primary-200, #bae6fd)';
                    }}
                  >
                    {/* Day name */}
                    <Text
                      variant="label"
                      weight="semibold"
                      color="var(--ggui-color-primary-600, #0284c7)"
                    >
                      {day.day}
                    </Text>

                    {/* Weather icon/emoji */}
                    <div
                      style={{
                        fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                        margin: 'var(--ggui-spacing-sm, 8px) 0',
                      }}
                    >
                      {getWeatherEmoji(day.condition)}
                    </div>

                    {/* Temps */}
                    <Stack direction="vertical" gap={2}>
                      <div
                        style={{
                          fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                          fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                          color: 'var(--ggui-color-primary-700, #0369a1)',
                        }}
                      >
                        {day.high}°
                      </div>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-text-secondary, #6b7280)"
                      >
                        {day.low}°
                      </Text>
                    </Stack>
                  </div>
                );
              })}
            </div>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Text, Row, Divider } from '@ggui-ai/design/primitives';

interface ForecastDay {
  date: string; // e.g., "Mon"
  icon: string; // e.g., "☀️"
  high: number;
  low: number;
}

interface WeatherCardProps {
  city?: string;
  temperature?: number;
  condition?: string;
  conditionIcon?: string; // e.g., "☀️"
  humidity?: number; // percentage
  windSpeed?: number; // km/h or mph
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "Unknown",
  temperature = 20,
  condition = "Partly Cloudy",
  conditionIcon = "🌤️",
  humidity = 60,
  windSpeed = 15,
  forecast = [
    { date: "Mon", icon: "☀️", high: 25, low: 15 },
    { date: "Tue", icon: "☁️", high: 22, low: 14 },
    { date: "Wed", icon: "🌧️", high: 18, low: 10 },
    { date: "Thu", icon: "☀️", high: 24, low: 13 },
    { date: "Fri", icon: "🌬️", high: 20, low: 12 },
  ],
  onSubmit
}: WeatherCardProps) {
  return (
    <Card
      padding="var(--ggui-spacing-lg, 24px)"
      shadow="md"
      style={{
        borderRadius: 'var(--ggui-radius-lg, 12px)',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
        maxWidth: '400px', // Max width for card responsiveness
        width: '100%',
      }}
    >
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-lg, 24px)"
        role="region"
        aria-label={"Weather information card for " + city}
      >
        {/* City Name */}
        <Text
          variant="h2"
          align="center"
          style={{
            color: 'var(--ggui-color-text-primary, #111827)',
            fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
          }}
        >
          {city}
        </Text>

        {/* Main Weather Display */}
        <Row align="center" justify="center" gap="var(--ggui-spacing-md, 16px)">
          <Text
            style={{
              fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
              fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: '1',
            }}
          >
            {temperature}°
          </Text>
          <Stack direction="vertical" align="start" gap="var(--ggui-spacing-xs, 4px)">
            <Text
              style={{
                fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                lineHeight: '1',
              }}
            >
              {conditionIcon}
            </Text>
            <Text
              variant="h3"
              style={{
                color: 'var(--ggui-color-text-primary, #111827)',
                fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
              }}
            >
              {condition}
            </Text>
          </Stack>
        </Row>

        {/* Details Section (Humidity, Wind Speed) */}
        <Stack direction="horizontal" justify="around" style={{ padding: 'var(--ggui-spacing-sm, 8px)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-xs, 4px)" align="center">
            <Text
              style={{
                color: 'var(--ggui-color-text-secondary, #6b7280)',
                fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
              }}
            >
              Humidity:
            </Text>
            <Text
              weight="semibold"
              style={{
                color: 'var(--ggui-color-text-primary, #111827)',
                fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
              }}
            >
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="horizontal" gap="var(--ggui-spacing-xs, 4px)" align="center">
            <Text
              style={{
                color: 'var(--ggui-color-text-secondary, #6b7280)',
                fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
              }}
            >
              Wind:
            </Text>
            <Text
              weight="semibold"
              style={{
                color: 'var(--ggui-color-text-primary, #111827)',
                fontSize: 'var(--ggui-typography-fontSize-base, 16px)',
              }}
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider
          style={{
            margin: '0', // Override default margin
            borderColor: 'var(--ggui-color-gray-200, #e5e7eb)',
          }}
        />

        {/* 5-Day Forecast Strip */}
        <Row
          justify="around"
          style={{
            padding: 'var(--ggui-spacing-sm, 8px)',
            backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
            borderRadius: 'var(--ggui-radius-md, 8px)',
          }}
        >
          {forecast.map((day, index) => (
            <Stack
              direction="vertical"
              align="center"
              gap="var(--ggui-spacing-xs, 4px)"
              key={day.date}
              style={{
                flexShrink: 0,
                padding: 'var(--ggui-spacing-xs, 4px)',
                minWidth: '60px', // Ensure items don't get too squished
              }}
            >
              <Text
                variant="caption"
                weight="semibold"
                style={{
                  color: 'var(--ggui-color-primary-800, #075985)',
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                }}
              >
                {day.date}
              </Text>
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                }}
              >
                {day.icon}
              </Text>
              <Text
                variant="caption"
                style={{
                  color: 'var(--ggui-color-text-secondary, #6b7280)',
                  fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                }}
              >
                {day.high}° / {day.low}°
              </Text>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}
